    .state = CONTROLLER_STATE_SAFE_VENT,
    .has_valid_pressure = false,
    .last_pressure_kpa = 0,
    .last_pressure_ms = 0U,
    .has_valid_door = false,
    .door_closed = false,
    .last_door_ms = 0U,
};

// Initialize the controller
void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // Default state: safe vent-open (compressor off, vent open)
    s_controller.compressor_on = false;
    s_controller.vent_open = true;
    s_controller.state = CONTROLLER_STATE_SAFE_VENT;
    s_controller.has_valid_pressure = false;
    s_controller.last_pressure_kpa = 0;
    s_controller.last_pressure_ms = 0U;
    s_controller.has_valid_door = false;
    s_controller.door_closed = false;
    s_controller.last_door_ms = 0U;
}

// Set to safe vent-open state (compressor off, vent open)
static void controller_set_safe_vent(controller_output_t *output)
{
    output->compressor_on = false;
    output->vent_open = true;
    s_controller.state = CONTROLLER_STATE_SAFE_VENT;
}

// Set to pressurizing state (compressor on, vent closed)
static void controller_set_pressurizing(controller_output_t *output)
{
    output->compressor_on = true;
    output->vent_open = false;
    s_controller.state = CONTROLLER_STATE_PRESSURIZING;
}

// Set to relieving state (compressor off, vent open)
static void controller_set_relieving(controller_output_t *output)
{
    output->compressor_on = false;
    output->vent_open = true;
    s_controller.state = CONTROLLER_STATE_RELIEVING;
}

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .changed = false,
        .timed_out = false,
    };

    // Initialize output with current state values for comparison
    output.compressor_on = s_controller.compressor_on;
    output.vent_open = s_controller.vent_open;
    output.state = s_controller.state;

    bool previous_compressor_on = s_controller.compressor_on;
    bool previous_vent_open = s_controller.vent_open;
    controller_state_t previous_state = s_controller.state;

    // Process the input based on kind
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        // Update pressure freshness
        s_controller.has_valid_pressure = true;
        s_controller.last_pressure_kpa = input.pressure_kpa;
        s_controller.last_pressure_ms = input.now_ms;

        // Only act on pressure if door is valid and closed
        if (s_controller.has_valid_door && s_controller.door_closed) {
            if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure with door closed: pressurize
                controller_set_pressurizing(&output);
            } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure with door closed: relieve
                controller_set_relieving(&output);
            } else {
                // In the 40-60 band: hold previous safe output
                output.state = CONTROLLER_STATE_HOLDING;
            }
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        // Update door freshness and state
        s_controller.has_valid_door = true;
        s_controller.door_closed = false;
        s_controller.last_door_ms = input.now_ms;

        // Door open forces safe vent-open state
        controller_set_safe_vent(&output);
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        // Update door freshness and state
        s_controller.has_valid_door = true;
        s_controller.door_closed = true;
        s_controller.last_door_ms = input.now_ms;

        // Door closed: check pressure if we have valid pressure reading
        if (s_controller.has_valid_pressure) {
            if (s_controller.last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure with door closed: pressurize
                controller_set_pressurizing(&output);
            } else if (s_controller.last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure with door closed: relieve
                controller_set_relieving(&output);
            } else {
                // In the 40-60 band: hold previous safe output
                output.state = CONTROLLER_STATE_HOLDING;
            }
        }
        // If we don't have valid pressure yet, stay in safe vent state
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        // Timeout or invalid input forces safe vent-open
        controller_set_safe_vent(&output);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No new input, check for timeouts and maintain state
        break;
    }

    // Check for timeout condition: either sensor stale for more than 1000ms
    bool pressure_stale = false;
    bool door_stale = false;

    if (s_controller.has_valid_pressure && 
        (input.now_ms - s_controller.last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        pressure_stale = true;
    }

    if (s_controller.has_valid_door && 
        (input.now_ms - s_controller.last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        door_stale = true;
    }

    // If either sensor is stale, go to safe vent state
    if (pressure_stale || door_stale) {
        controller_set_safe_vent(&output);
        output.timed_out = true;
    }

    // Update the controller's stored state
    s_controller.compressor_on = output.compressor_on;
    s_controller.vent_open = output.vent_open;

    // Determine if output changed from previous values
    if (output.compressor_on != previous_compressor_on || 
        output.vent_open != previous_vent_open) {
        output.changed = true;
    }

    return output;
}

// Get state name for a given state
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return CONTROLLER_STATE_NAME_SAFE_VENT;
    case CONTROLLER_STATE_PRESSURIZING:
        return CONTROLLER_STATE_NAME_PRESSURIZING;
    case CONTROLLER_STATE_HOLDING:
        return CONTROLLER_STATE_NAME_HOLDING;
    case CONTROLLER_STATE_RELIEVING:
        return CONTROLLER_STATE_NAME_RELIEVING;
    default:
        return CONTROLLER_STATE_NAME_SAFE_VENT;
    }
}

